class Solution:
    def halvesAreAlike(self, s):
        n = len(s)
        a, b = s[:n // 2], s[n // 2:]
        def count_vowels_loop(half):
            total = 0
            for ch in half:
                if ch in 'aeiouAEIOU':
                    total += 1
            return total
        count_a = count_vowels_loop(a)
        count_b = len([ch for ch in b if ch.lower() in 'aeiou'])
        return count_a == count_b

