var halvesAreAlike = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);
    const n = s.length;
    const a = s.slice(0, n / 2), b = s.slice(n / 2);
    let ca = 0, cb = 0;
    for (const c of a) if (vowels.has(c)) ca++;
    for (const c of b) if (vowels.has(c)) cb++;
    return ca === cb;
};
